<?phpnamespace app\module\User;//导入部分use app\dep\AddressDep;use app\dep\User\PermissionDep;use app\dep\User\RoleDep;use app\dep\User\UsersDep;use app\dep\User\UsersTokenDep;use app\enum\CommonEnum;use app\enum\EmailEnum;use app\enum\PermissionEnum;use app\enum\SexEnum;use app\module\BaseModule;use app\service\DictService;use app\service\ExportService;use Carbon\Carbon;use support\Cache;use Webman\RedisQueue\Redis;use PhpOffice\PhpSpreadsheet\Spreadsheet;use PhpOffice\PhpSpreadsheet\Writer\Xlsx;class UsersModule extends BaseModule{    public $UserDep;    public $UserTokenDep;    public $RoleDep;    public $PermissionDep;    public $AddressDep;    public function __construct()    {        $this->UserDep = new UsersDep();        $this->UserTokenDep = new UsersTokenDep();        $this->RoleDep = new RoleDep();        $this->PermissionDep = new PermissionDep();        $this->AddressDep = new AddressDep();    }    public function register($request)    {        $param = $request->all();        $dep = $this->UserDep;        $tokenDep = $this->UserTokenDep;        foreach (['username', 'email', 'password', 'respassword', 'code'] as $f) {            if (empty($param[$f])) {                return self::response([], "{$f} 不能为空", 100);            }        }        // 用 MD5 生成安全的缓存 key        $cacheKey = 'email_code_' . md5($param['email']);        $code = Cache::get($cacheKey);        if ($code != $param['code']) {            return self::response([], '验证码错误', 100);        }        $resdep = $dep->firstByEmail($param['email']);        if ($resdep) {            return self::response([], '邮箱已存在', 100);        }        if ($param['password'] != $param['respassword']) {            return self::response([], '密码不一致', 100);        }        // 创建随机 token        $token = md5(uniqid(rand(), true));        // 设置 token 过期时间，一周后        $expire_time = Carbon::now()->addWeek()->toDateTimeString();        $data = [            'email' => $param['email'],            'password' => password_hash($param['password'], PASSWORD_DEFAULT),            'username' => $param['username'],        ];        $userId = $dep->add($data);        $tokenData = [            'user_id' => $userId,            'token' => $token,            'expires_in' => $expire_time,            'ip' => $request->getRealIp(),        ];        $tokenDep->add($tokenData);        $data1 = [            'token' => $token,        ];        return self::response($data1);    }    public function login($request)    {        $param = $request->all();        $dep = $this->UserDep;        $tokenDep = $this->UserTokenDep;        foreach (['email', 'password'] as $f) {            if (empty($param[$f])) {                return self::response([], "{$f} 不能为空", 100);            }        }        $resDep = $dep->firstByEmail($param['email']);        if (!$resDep) {            return self::response([], '邮箱不存在', 100);        }        if (!password_verify($param['password'], $resDep['password'])) {            return self::response([], '密码不正确', 100);        }        //创建一个随机token,命名为$token        $token = md5(uniqid(rand(), true));        //创建token过期时间，为创建token的一周        $expire_time = Carbon::now()->addWeek()->toDateTimeString();        $data = [            'token' => $token,            'expires_in' => $expire_time,            'ip' => $request->getRealIp(),        ];        $tokenDep->editByUserId($resDep['id'], $data);        $data1 = [            'token' => $token,        ];        return self::response($data1);    }    public function sendCode($request)    {        $param = $request->all();        if (empty($param['email'])) {            return self::response([], '邮箱不能为空', 100);        }        if (!isValidEmail($param['email'])) {            return self::response([], '邮箱不合法', 100);        }        // 生成验证码        $code = rand(100000, 999999);        // 获取邮件主题，防止状态传值错误，建议加个 isset 判断        $theme = isset(EmailEnum::$statusArr[$param['status']]) ? EmailEnum::$statusArr[$param['status']] : '默认主题';        $queue = "email-send";        $data = [            'email' => $param['email'],            'theme' => $theme,            'code' => $code,        ];        Redis::send($queue, $data);        // 使用 MD5 对 email 进行哈希，保证缓存 key 中没有特殊字符        $cacheKey = 'email_code_' . md5($param['email']);        // 设置验证码缓存，5 分钟有效，300 秒        Cache::set($cacheKey, $code, 300);        return self::response([], '验证码发送成功');    }    public function forgetPassword($request)    {        $param = $request->all();        $dep = $this->UserDep;        foreach (['email', 'newpassword', 'code'] as $f) {            if (empty($param[$f])) {                return self::response([], "{$f} 不能为空", 100);            }        }        // 用 MD5 生成缓存 key，保持与 sendCode 中一致        $cacheKey = 'email_code_' . md5($param['email']);        $code = Cache::get($cacheKey);        if ($code != $param['code']) {            return self::response([], '验证码错误', 100);        }        $resdep = $dep->firstByEmail($param['email']);        $data = [            'password' => password_hash($param['newpassword'], PASSWORD_DEFAULT),        ];        $dep->edit($resdep->id, $data);        return self::response();    }    public function init($request)    {        $user = $this->UserDep->first($request->userId);        if (!$user) {            return self::response([], '用户不存在', 100);        }        $data = [            'user_id'  => $user->id,            'username' => $user->username,            'avatar'   => $user->avatar,        ];        // 叶子级权限 ID 列表        $resRole = $this->RoleDep->first($user->role_id);        $leafIds = json_decode($resRole->permission_id, true);        if (empty($leafIds) || !is_array($leafIds)) {            return self::response(array_merge($data, [                'permissions' => [],                'router'      => [],                'buttons'     => []            ]));        }        // 获取所有权限（数组），包含 type, code        $allPerms = $this->PermissionDep->getAllPermissions();        $permMap  = array_column($allPerms, null, 'id');        // 收集需保留的目录/页面/按钮 ID        $includeIds = [];        foreach ($leafIds as $leafId) {            $cur = $leafId;            while (isset($permMap[$cur]) && !in_array($cur, $includeIds, true)) {                $includeIds[] = $cur;                $parent = $permMap[$cur]['parent_id'];                if ($parent === -1 || !isset($permMap[$parent])) break;                $cur = $parent;            }        }        // ✅ 构造权限树（type=1 或 type=2）        $menusData = array_filter($allPerms, fn($p) =>            in_array($p['id'], $includeIds, true) &&            in_array($p['type'], [PermissionEnum::TYPE_DIR, PermissionEnum::TYPE_PAGE])        );        $menus = $this->buildPermissionTree($menusData, -1);        // ✅ 构造前端路由（只保留 type = 页面（2） 且有 path & component）        $router = [];        foreach ($menusData as $m) {            if (                $m['type'] == PermissionEnum::TYPE_PAGE &&                !empty($m['path']) &&                !empty($m['component'])            ) {                $router[] = [                    'name'      => $m['path'],                    'path'      => $m['path'],                    'component' => $m['component'],                    'meta'      => [                        'menuId' => (string)$m['id']                    ],                ];            }        }        // ✅ 构造按钮权限（type = 3）        $buttons = [];        foreach ($leafIds as $id) {            if (isset($permMap[$id]) && $permMap[$id]['type'] == PermissionEnum::TYPE_BUTTON) {                $buttons[] = [                    'id'   => $id,                    'code' => $permMap[$id]['code'],                ];            }        }        return self::response(array_merge($data, [            'permissions' => $menus,            'router'      => $router,            'buttons'     => $buttons,        ]));    }    private function buildPermissionTree(array $items, $parentId)    {        $tree = [];        foreach ($items as $item) {            if ($item['parent_id'] === $parentId) {                $children = $this->buildPermissionTree($items, $item['id']);                $node     = [                    'index'    => (string)$item['id'],                    'label'    => $item['name'],                    'path'     => $item['path'],                    'icon'     => $item['icon'],                    'children' => [],                ];                if (!empty($children)) {                    $node['children'] = $children;                }                $tree[] = $node;            }        }        return $tree;    }    public function initPersonal($request)    {        $param = $request->all();        $dictService = new DictService();        $user = $this->UserDep->first($param['user_id']);;        $resRole = $this->RoleDep->first($user->role_id);        $data['list'] = [            'username' => $user->username,            'email' => $user->email,            'avatar' => $user->avatar,            'phone' => $user->phone,            'role_id' => $user->role_id,            'role_name' => $resRole['name'],            'address' => json_decode($user->address),            'detail_address' => $user->detail_address,            'sex' => $user->sex,            'desc' => $user->desc,            'is_self' => $param['user_id'] == $request->userId ? CommonEnum::YES : CommonEnum::NO,        ];        $dict = $dictService            ->setAuthAdressTree()            ->setSexArr()            ->getDict();        $data['dict'] = $dict;        return self::response($data);    }    public function editPersonal($request)    {        $param = $request->all();        $dep = $this->UserDep;        $user = $this->UserDep->first($request->userId);;        if (empty($param['username'])        ) {            return self::response([], '必填项不能为空', 100);        }        // 验证手机号        if (isset($param['phone']) && !is_valid_phone_number($param['phone'])) {            return self::response([], '无效的手机号码', 100);        }        $data = [            'username' => $param['username'],            'avatar' => $param['avatar'],            'phone' => $param['phone'] ?? '',            'sex' => $param['sex'],            'address' => json_encode($param['address']),            'detail_address' => $param['detail_address'] ?? '',            'desc' => $param['desc'],        ];        $dep->edit($user->id, $data);        return self::response();    }    public function EditPassword($request)    {        $param = $request->all();        $dep = $this->UserDep;        $user = $this->UserDep->first($request->userId);;        // 检查必填项是否为空        foreach (['password', 'newpassword', 'respassword'] as $f) {            if (empty($param[$f])) {                return self::response([], "{$f} 不能为空", 100);            }        }        // 验证原密码是否正确        if (!password_verify($param['password'], $user->password)) {            return self::response([], '原密码不正确', 100);        }        // 确保新密码与确认密码一致        if ($param['newpassword'] !== $param['respassword']) {            return self::response([], '新密码不一致', 100);        }        // 防止新密码与原密码相同        if (password_verify($param['newpassword'], $user->password)) {            return self::response([], '新密码不能与原密码一致', 100);        }        // 加密新密码        $data = [            'password' => password_hash($param['newpassword'], PASSWORD_DEFAULT),        ];        // 更新密码        $dep->edit($user->id, $data);        return self::response([], '密码修改成功', 200);    }    public function initList()    {        $dictService = new DictService();        $dict = $dictService            ->setRoleArr()            ->setAuthAdressTree()            ->setSexArr()            ->getDict();        $data['dict'] = $dict;        return self::response($data);    }    public function editList($request)    {        $param = $request->all();        $dep = $this->UserDep;        if (empty($param['username'])) {            return self::response([], '用户名不能为空', 100);        }        $data = [            'username' => $param['username'],            'avatar' => $param['avatar'],            'role_id' => $param['role_id'],            'sex' => $param['sex'],            'address' => json_encode($param['address']) ?? '[]',            'detail_address' => $param['detail_address'] ?? '',            'desc' => $param['desc'],        ];        $dep->edit($param['id'], $data);        return self::response();    }    public function delList($request)    {        $param = $request->all();        $dep = $this->UserDep;        $dep->del($param['id'], ['is_del' => CommonEnum::YES]);        return self::response();    }    public function listList($request)    {        $dep = $this->UserDep;        $RoleDep = $this->RoleDep;        $AddressDep = $this->AddressDep;        $UserTokenDep = $this->UserTokenDep;        $param = $request->all();        $param['page_size'] = isset($param['page_size']) ? $param['page_size'] : 50;        $param['current_page'] = isset($param['current_page']) ? $param['current_page'] : 1;        $resList = $dep->list($param);        $data['list'] = $resList->map(function ($item) use ($RoleDep, $AddressDep, $UserTokenDep) {            $resRole = $RoleDep->first($item->role_id);            $resUserToken = $UserTokenDep->firstByUserId($item->id);            $addressIDs = json_decode($item->address);            $address = '';            foreach ($addressIDs as $addressID) {                $resAddress = $AddressDep->first($addressID);                $address .= $resAddress->name . '-';            }            $address .= $item->detail_address;            return [                'id' => $item->id,                'uid' => $item->uid,                'username' => $item->username,                'email' => $item->email,                'avatar' => $item->avatar,                'phone' => $item->phone,                'sex' => $item->sex,                'sex_show' => SexEnum::$SexArr[$item->sex],                'role_id' => $item->role_id,                'desc' => $item->desc,                'role_name' => $resRole->name,                'address_show' => $address,                'address' => json_decode($item->address),                'detail_address' => $item->detail_address,                'expires_in' => $resUserToken->expires_in,                'is_expired' => $resUserToken['expires_in'] < Carbon::now()->toDateTimeString() ? '已过期' : '未过期',                'created_at' => $item['created_at']->toDateTimeString(),            ];        });        $data['page'] = [            'page_size' => $param['page_size'],            'current_page' => $param['current_page'],            'total_page' => $resList->lastPage(),            'total' => $resList->total(),        ];        return self::response($data);    }    public function batchEditList($request)    {        $param = $request->all();        $dep = $this->UserDep;        $id = $param['ids'];        if ($param['field'] == 'sex') {            if (empty($param['sex'])) {                return self::response([], '性别不能为空', 100);            }            $data = [                'sex' => $param['sex'],            ];            $dep->edit($id, $data);        }        if ($param['field'] == 'address') {            if (empty($param['address'])) {                return self::response([], '地址不能为空', 100);            }            $data = [                'address' => json_encode($param['address']),            ];            $dep->edit($id, $data);        }        if ($param['field'] == 'detail_address') {            if (empty($param['detail_address'])) {                return self::response([], '详细地址不能为空', 100);            }            $data = [                'detail_address' => $param['detail_address'],            ];            $dep->edit($id, $data);        }        return self::response();    }    public function exportList($request)    {        // 1. 获取前端传入的 ids        $ids = $request->input('ids', []);        if (empty($ids) || !is_array($ids)) {            return self::response(['code' => 400, 'msg' => '参数错误，缺少 ids']);        }        // 2. 获取用户数据        $users = $this->UserDep->getUsersByIds($ids);        $roleDep = $this->RoleDep;        // 3. 配置表头 ['字段名' => '列标题']        $headers = [            'id'       => '用户ID',            'username' => '用户名',            'email'    => '邮箱',            'phone'    => '手机号',            'avatar'   => '头像',            'sex'      => '性别',            'role'     => '角色',        ];        $data = $users->map(function ($item) use ($roleDep) {            $resRole = $roleDep->first($item->role_id);            return [                'id'       => $item->id,                'username' => $item->username,                'email'    => $item->email,                'phone'    => $item->phone,                'avatar'   => $item->avatar,                'sex'      => SexEnum::$SexArr[$item->sex],                'role'     => $resRole['name'],            ];        })->toArray();        // 4. 调用导出服务        $exportService = new ExportService();        $url = $exportService->export($headers, $data, 'users_export');        return self::response(['url' => $url]);    }}